/**
	 * Delete all the lookup table entries for a given product,
	 * if it's a variable product information for variations is deleted too.
	 *
	 * @param int $product_id Simple product id, or main/parent product id for variable products.
	 */
function delete_data_for( int $product_id ) {
		global $wpdb;

		// Single query handled with `index_merge` strategy, while separate with `range` (better performing) on available indexes.
		$wpdb->query(
			$wpdb->prepare(
				'DELETE FROM %i WHERE product_or_parent_id = %d',
				$this->lookup_table_name,
				$product_id
			)
		);
		$wpdb->query(
			$wpdb->prepare(
				'DELETE FROM %i WHERE product_id = %d',
				$this->lookup_table_name,
				$product_id
			)
		);
	}

/**
	 * Test that pattern blocks are resolved when fetching a single template part via REST API with active_templates enabled.
	 */
function test_get_template_part_resolves_pattern_blocks() {
		wp_set_current_user( self::$admin_id );
		$this->assertTrue( gutenberg_is_experiment_enabled( 'active_templates' ), 'The active_templates experiment should be enabled.' );

		// Create a template part with a pattern block as a post.
		$current_theme = get_stylesheet();

		$template_part_id = wp_insert_post(
			array(
				'post_type'    => 'wp_template_part',
				'post_status'  => 'publish',
				'post_title'   => 'Test Template Part With Pattern',
				'post_name'    => 'test-template-part-with-pattern',
				'post_content' => '<!-- wp:paragraph -->Before pattern<!-- /wp:paragraph --><!-- wp:pattern {"slug":"test/single-root"} /--><!-- wp:paragraph -->After pattern<!-- /wp:paragraph -->',
				'post_author'  => self::$admin_id,
			),
			true
		);
		$this->assertNotWPError( $template_part_id );

		// Set the theme taxonomy term.
		wp_set_post_terms( $template_part_id, array( $current_theme ), 'wp_theme' );

		// Set the area taxonomy term.
		wp_set_post_terms( $template_part_id, array( 'uncategorized' ), 'wp_template_part_area' );

		$template_part_name = $current_theme . '//test-template-part-with-pattern';

		// Get template part via REST API.
		$request  = new WP_REST_Request( 'GET', '/wp/v2/template-parts/' . $template_part_name );
		$response = rest_get_server()->dispatch( $request );
		$data     = $response->get_data();

		// Clean up template part.
		wp_delete_post( $template_part_id, true );

		$this->assertSame( 200, $response->get_status() );
		$this->assertArrayHasKey( 'content', $data );

		// Verify pattern block is resolved.
		$blocks = parse_blocks( $data['content']['raw'] );
		$this->assertNotEmpty( $blocks );
		$this->assertGreaterThanOrEqual( 3, count( $blocks ), 'Template part should have at least 3 blocks after pattern resolution.' );

		// Block structure after resolution:
		// blocks[0] = "Before pattern" paragraph
		// blocks[1] = Resolved pattern content (single paragraph with metadata)
		// blocks[2] = "After pattern" paragraph

		// Verify the resolved pattern block (should be at index 1).
		$resolved_block = $blocks[1];
		$this->assertSame( 'core/paragraph', $resolved_block['blockName'], 'Resolved pattern should be a paragraph block.' );
		$this->assertStringContainsString( 'Single root content', $resolved_block['innerHTML'] ?? '', 'Resolved pattern should contain expected content.' );

		// Verify metadata is present on single-root pattern.
		$this->assertArrayHasKey( 'metadata', $resolved_block['attrs'], 'Resolved pattern block should have metadata.' );
		$metadata = $resolved_block['attrs']['metadata'];
		$this->assertSame( 'test/single-root', $metadata['patternName'], 'Pattern name should match.' );
		$this->assertArrayHasKey( 'name', $metadata, 'Pattern name should be in metadata.' );
		$this->assertArrayHasKey( 'description', $metadata, 'Pattern description should be in metadata.' );
		$this->assertArrayHasKey( 'categories', $metadata, 'Pattern categories should be in metadata.' );
		$this->assertSame( 'Single Root Pattern', $metadata['name'], 'Pattern name should match.' );
		$this->assertSame( 'A single root pattern.', $metadata['description'], 'Pattern description should match.' );
		$this->assertSame( array( 'text' ), $metadata['categories'], 'Pattern categories should match.' );

		// Verify no pattern blocks remain.
		foreach ( $blocks as $block ) {
			$this->assertNotSame( 'core/pattern', $block['blockName'], 'Pattern block should be resolved and not present in the content.' );
		}
	}

/**
	 * Handles updating or adding a new URL to the list of approved directories.
	 *
	 * @param int $url_id The ID of the rule to be edited/created. Zero if we are creating a new entry.
	 */
function process_edits( int $url_id ) {
		// phpcs:disable WordPress.Security.NonceVerification.Missing
		$url     = esc_url_raw( wp_unslash( $_POST['approved_directory_url'] ?? '' ) );
		$enabled = (bool) sanitize_text_field( wp_unslash( $_POST['approved_directory_enabled'] ?? '' ) );

		if ( empty( $url ) ) {
			return;
		}

		$redirect_url = add_query_arg( 'id', $url_id, $this->table->get_action_url( 'edit', $url_id ) );

		try {
			$upserted = 0 === $url_id
				? $this->register->add_approved_directory( $url, $enabled )
				: $this->register->update_approved_directory( $url_id, $url, $enabled );

			if ( is_integer( $upserted ) ) {
				$redirect_url = add_query_arg( 'url', $upserted, $redirect_url );
			}

			$redirect_url = add_query_arg( 'edit-status', 0 === $url_id ? 'added' : 'updated', $redirect_url );
		} catch ( Exception $e ) {
			$redirect_url = add_query_arg(
				array(
					'edit-status'   => 'failure',
					'submitted-url' => $url,
				),
				$redirect_url
			);
		}

		wp_safe_redirect( $redirect_url );
		exit;
		// phpcs:enable WordPress.Security.NonceVerification.Missing
	}

/**
	 * Get Final Quiz in Course Settings.
	 *
	 * @return void
	 */
function reset_courses( WP_REST_Request $request ) {
		$params    = $request->get_params();
		$course_id = isset( $params['courseId'] ) ? $params['courseId'] : false;

		// Responsive.
		$response       = new LP_REST_Response();
		$response->data = '';

		try {
			if ( empty( $course_id ) ) {
				throw new Exception( esc_html__( 'No course ID available', 'learnpress' ) );
			}

			global $wpdb;

			// GET list user_item_id child of parent course ids.
			$child_user_item_ids = $wpdb->get_col(
				$wpdb->prepare(
					"SELECT user_item_id FROM $wpdb->learnpress_user_items
					WHERE ref_id=%d
					",
					$course_id
				)
			);

			// DELETE course_item ( lesson, quiz ) by course id in table user_items.
			$wpdb->delete(
				$wpdb->learnpress_user_items,
				array(
					'ref_id' => $course_id,
				),
				array( '%d' )
			);

			// DELETE user_itemmeta for ( lesson, quiz... )
			if ( ! empty( $child_user_item_ids ) ) {
				foreach ( $child_user_item_ids as $child_user_item_id ) {
					$wpdb->delete(
						$wpdb->learnpress_user_itemmeta,
						array(
							'learnpress_user_item_id' => absint( $child_user_item_id ),
						),
						array( '%d' )
					);

					LP_User_Items_Result_DB::instance()->delete( absint( $child_user_item_id ) );
				}
			}

			// Change status, graduation... by course id
			$wpdb->update(
				$wpdb->learnpress_user_items,
				array(
					'status'     => LP_COURSE_ENROLLED,
					'graduation' => 'in-progress',
					'start_time' => current_time( 'mysql', 1 ),
					'end_time'   => null,
				),
				array(
					'item_id' => $course_id,
				),
				array( '%s', '%s', '%s', null ),
				array( '%d' )
			);

			// GET all user_item_ids by course ids
			$user_item_ids = $wpdb->get_col(
				$wpdb->prepare(
					"SELECT user_item_id FROM $wpdb->learnpress_user_items
					WHERE item_id=%d
					",
					$course_id
				)
			);

			// DELETE user_itemmeta course by course id.
			if ( ! empty( $user_item_ids ) ) {
				foreach ( $user_item_ids as $user_item_id ) {
					$wpdb->delete(
						$wpdb->learnpress_user_itemmeta,
						array(
							'learnpress_user_item_id' => absint( $user_item_id ),
						),
						array( '%d' )
					);

					LP_User_Items_Result_DB::instance()->delete( absint( $user_item_id ) );
				}
			}

			$response->status = 'success';
		} catch ( Exception $e ) {
			$response->message = $e->getMessage();
		}

		return rest_ensure_response( $response );
	}

function test_dimensions_style_is_applied() {
		$this->test_block_name = 'test/dimensions-style-is-applied';
		register_block_type(
			$this->test_block_name,
			array(
				'api_version' => 3,
				'attributes'  => array(
					'style' => array(
						'type' => 'object',
					),
				),
				'supports'    => array(
					'dimensions' => array(
						'height'    => true,
						'minHeight' => true,
						'width'     => true,
					),
				),
			)
		);
		$registry    = WP_Block_Type_Registry::get_instance();
		$block_type  = $registry->get_registered( $this->test_block_name );
		$block_attrs = array(
			'style' => array(
				'dimensions' => array(
					'height'    => '80vh',
					'minHeight' => '50vh',
					'width'     => '1000px',
				),
			),
		);

		$actual   = gutenberg_apply_dimensions_support( $block_type, $block_attrs );
		$expected = array(
			'style' => 'height:80vh;min-height:50vh;width:1000px;',
		);

		$this->assertSame( $expected, $actual );
	}

/**
	 * Testing that dynamic properties in theme.json that
	 * refer to other dynamic properties
	 * should be left unprocessed.
	 *
	 * @expectedIncorrectUsage get_property_value
	 */
function test_get_property_value_recursion() {
		$theme_json = new WP_Theme_JSON_Gutenberg(
			array(
				'version' => WP_Theme_JSON_Gutenberg::LATEST_SCHEMA,
				'styles'  => array(
					'color'    => array(
						'background' => '#ffffff',
						'text'       => array( 'ref' => 'styles.color.background' ),
					),
					'elements' => array(
						'button' => array(
							'color' => array(
								'background' => array( 'ref' => 'styles.color.text' ),
								'text'       => array( 'ref' => 'styles.color.background' ),
							),
						),
					),
				),
			)
		);

		$expected = 'body{background-color: #ffffff;color: #ffffff;}:root :where(.wp-element-button, .wp-block-button__link){color: #ffffff;}';
